import React, { useState, useMemo, useEffect } from 'react';
import { Ico } from './Icons';
import { EmptyState } from './EmptyState';
import { Modal } from './Modal';
import api from '../../services/api';
import { Toast } from './Toast';
import { removeAccents } from './Shared';

export const SimplePage = ({ title, subtitle, icon, cols, emptyTitle, emptyDesc, renderRow, emptyForm, renderForm, validate, initialData = [], tabs, renderGridItem, renderActions, stats: statsProp, apiEndpoint, primaryKey = '_id', renderExtraActions, renderToolbarActions }) => {
    const [list, setList] = useState(initialData);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [modal, setModal] = useState(null);
    const [form, setForm] = useState(emptyForm);
    const [editId, setEditId] = useState(null);
    const [search, setSearch] = useState('');
    const [viewMode, setViewMode] = useState('table');
    const [activeTab, setActiveTab] = useState(tabs ? tabs[0].id : null);
    const [currentPage, setCurrentPage] = useState(1);
    const [itemsPerPage, setItemsPerPage] = useState(10);
    const [toasts, setToasts] = useState([]);

    const addToast = (type, message) => {
        const id = Date.now();
        setToasts(p => [...p, { id, type, message }]);
    };

    const removeToast = (id) => setToasts(p => p.filter(x => x.id !== id));

    const fetchData = async () => {
        if (!apiEndpoint) return;
        setLoading(true);
        try {
            const res = await api.get(apiEndpoint);
            setList(res.data.data || res.data);
            setError(null);
        } catch (err) {
            console.error('Fetch error:', err);
            setError('Không thể tải dữ liệu');
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        if (apiEndpoint) fetchData();
    }, [apiEndpoint]);

    const filtered = useMemo(() => {
        const term = removeAccents(search.toLowerCase());

        const checkValue = (val) => {
            if (val === null || val === undefined) return false;
            if (typeof val === 'object') {
                return Object.values(val).some(v => checkValue(v));
            }
            return removeAccents(String(val).toLowerCase()).includes(term);
        };

        let res = [...list].filter(x => checkValue(x));

        if (tabs && activeTab && activeTab !== 'all') {
            const currentTab = tabs.find(t => t.id === activeTab);
            if (currentTab?.filter) res = res.filter(currentTab.filter);
        }
        return res;
    }, [list, search, activeTab, tabs]);

    useEffect(() => {
        setCurrentPage(1);
    }, [search, activeTab, itemsPerPage]);

    const paginated = useMemo(() => {
        const start = (currentPage - 1) * itemsPerPage;
        return filtered.slice(start, start + itemsPerPage);
    }, [filtered, currentPage, itemsPerPage]);

    const totalPages = Math.ceil(filtered.length / itemsPerPage);

    const currentStats = useMemo(() => {
        if (!statsProp) return null;
        return typeof statsProp === 'function' ? statsProp(list) : statsProp;
    }, [list, statsProp]);

    const openAdd = () => { setForm(emptyForm); setModal('add'); };
    const openEdit = (item) => {
        setForm(Object.fromEntries(Object.keys(emptyForm).map(k => [k, item[k] ?? emptyForm[k]])));
        setEditId(item[primaryKey]);
        setModal('edit');
    };
    const openView = (item) => {
        setForm(Object.fromEntries(Object.keys(emptyForm).map(k => [k, item[k] ?? emptyForm[k]])));
        setModal('view');
    };
    const close = () => { setModal(null); setEditId(null); };
    const hc = (e) => {
        const { name, value, type, checked } = e.target;
        setForm(p => ({ ...p, [name]: type === 'checkbox' ? checked : value }));
    };

    const save = async () => {
        if (validate) {
            const errs = validate(form);
            if (errs) { alert(errs); return; }
        }

        try {
            if (modal === 'add') {
                const res = await api.post(apiEndpoint, form);
                setList(p => [...p, res.data.data || res.data]);
            } else {
                const res = await api.put(`${apiEndpoint}/${editId}`, form);
                const updated = res.data.data || res.data;
                setList(p => p.map(x => x[primaryKey] === editId ? updated : x));
            }
            close();
            addToast('success', `${modal === 'add' ? 'Thêm' : 'Cập nhật'} thành công!`);
        } catch (err) {
            console.error('Save error:', err);
            addToast('error', 'Lỗi khi lưu dữ liệu');
        }
    };

    const del = (id) => {
        setEditId(id);
        setModal('delete');
    };

    const executeDelete = async () => {
        try {
            await api.delete(`${apiEndpoint}/${editId}`);
            setList(p => p.filter(x => x[primaryKey] !== editId));
            addToast('success', 'Đã xóa bản ghi thành công!');
        } catch (err) {
            console.error('Delete error:', err);
            addToast('error', 'Lỗi khi xóa dữ liệu');
        } finally {
            close();
        }
    };

    return (
        <div className="simple-page">
            <div className="toast-container">
                {toasts.map(t => <Toast key={t.id} type={t.type} message={t.message} onClose={() => removeToast(t.id)} />)}
            </div>
            <div className="page-header">
                <div className="page-title-block">
                    <h1 className="page-title">{title}</h1>
                    <p className="page-subtitle">{typeof subtitle === 'function' ? subtitle(list) : subtitle}</p>
                </div>
                <div className="page-actions">
                    {renderExtraActions && renderExtraActions(fetchData, addToast, list)}
                    <button className="btn-primary" onClick={openAdd}>
                        {Ico.plus} <span>Thêm mới</span>
                    </button>
                </div>
            </div>

            {currentStats && (
                <div className="kpi-grid">
                    {currentStats.map((s, i) => (
                        <div key={i} className="kpi-card">
                            <div className="kpi-top">
                                <div className="kpi-icon" style={{ background: s.color + '22', color: s.color }}>
                                    {Ico[s.icon] || Ico.layoutGrid}
                                </div>
                            </div>
                            <div className="kpi-info">
                                <div className="kpi-label">{s.label}</div>
                                <div className="kpi-value">{s.value}</div>
                            </div>
                        </div>
                    ))}
                </div>
            )}

            <div className="page-toolbar">
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <div className="search-wrap">
                        <span className="search-icon">{Ico.search}</span>
                        <input className="search-input" placeholder="Tìm kiếm..." value={search} onChange={e => setSearch(e.target.value)} />
                    </div>
                    {renderToolbarActions && renderToolbarActions(fetchData, addToast, list)}
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                    <span className="table-count">{filtered.length} kết quả</span>
                    <select className="page-size-select" value={itemsPerPage} onChange={e => setItemsPerPage(Number(e.target.value))}>
                        <option value={5}>5 / trang</option>
                        <option value={10}>10 / trang</option>
                        <option value={20}>20 / trang</option>
                        <option value={50}>50 / trang</option>
                    </select>
                    <div className="view-switcher">
                        <button className={`view-btn ${viewMode === 'table' ? 'active' : ''}`} onClick={() => setViewMode('table')}>{Ico.layoutList}</button>
                        <button className={`view-btn ${viewMode === 'grid' ? 'active' : ''}`} onClick={() => setViewMode('grid')}>{Ico.layoutGrid}</button>
                    </div>
                </div>
            </div>

            <div className="data-card">
                {tabs && (
                    <div className="tab-bar">
                        {tabs.map(tab => (
                            <button key={tab.id} className={`tab-item ${activeTab === tab.id ? 'active' : ''}`} onClick={() => setActiveTab(tab.id)}>
                                {tab.label}
                            </button>
                        ))}
                    </div>
                )}

                <div className="page-content">
                    {viewMode === 'table' ? (
                        <table className="data-table">
                            <thead><tr>{cols.map((c, i) => <th key={i}>{c}</th>)}<th style={{ width: 80 }}></th></tr></thead>
                            <tbody>
                                {filtered.length === 0 && <tr><td colSpan={cols.length + 1}><EmptyState icon={icon} title={emptyTitle} desc={emptyDesc} /></td></tr>}
                                {paginated.map((item, i) => (
                                    <tr key={item[primaryKey] || i}>
                                        {renderRow(item, i, list, setList)}
                                        <td>
                                            <div className="actions-cell">
                                                {renderActions ? renderActions(item, openEdit, del, i, list, setList, addToast, openView) : (
                                                    <>
                                                        <button className="btn-action-ico" title="Xem" onClick={() => openView(item)}>{Ico.eye}</button>
                                                        <button className="btn-action-ico btn-edit" title="Sửa" onClick={() => openEdit(item)}>{Ico.edit}</button>
                                                        <button className="btn-action-ico btn-del" title="Xóa" onClick={() => del(item[primaryKey])}>{Ico.trash}</button>
                                                    </>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    ) : (
                        <div className="data-grid">
                            {filtered.length === 0 && <EmptyState icon={icon} title={emptyTitle} desc={emptyDesc} />}
                            {paginated.map((item, i) => renderGridItem ? renderGridItem(item, openEdit, del, i, list, setList, addToast, openView) : <div key={item[primaryKey] || i} className="grid-item-placeholder">Grid view content here</div>)}
                        </div>
                    )}
                </div>

                {totalPages > 1 && (
                    <div className="pagination">
                        <button className="page-btn" disabled={currentPage === 1} onClick={() => setCurrentPage(p => p - 1)}>{Ico.chevronLeft}</button>
                        <div className="page-numbers">
                            {[...Array(totalPages)].map((_, idx) => {
                                const pNum = idx + 1;
                                // Simple logic for dots could be added here, but staying simple for now
                                return (
                                    <button key={pNum} className={`page-num ${currentPage === pNum ? 'active' : ''}`} onClick={() => setCurrentPage(pNum)}>
                                        {pNum}
                                    </button>
                                );
                            })}
                        </div>
                        <button className="page-btn" disabled={currentPage === totalPages} onClick={() => setCurrentPage(p => p + 1)} style={{ transform: 'rotate(180deg)' }}>{Ico.chevronLeft}</button>
                    </div>
                )}
            </div>

            {modal && modal !== 'delete' && (
                <Modal title={modal === 'add' ? `Thêm ${title.toLowerCase()}` : modal === 'view' ? 'Chi tiết' : `Chỉnh sửa`} onClose={close} actions={<><button className="btn-secondary" onClick={close}>{modal === 'view' ? 'Đóng' : 'Hủy'}</button>{modal !== 'view' && <button className="btn-primary" onClick={save}>{modal === 'add' ? 'Thêm' : 'Lưu'}</button>}</>}>
                    {renderForm(form, hc, setForm, modal === 'view')}
                </Modal>
            )}

            {modal === 'delete' && (
                <Modal 
                    title="Xác nhận xóa" 
                    onClose={close} 
                    actions={
                        <>
                            <button className="btn-secondary" onClick={close}>Hủy bỏ</button>
                            <button className="btn-primary" style={{ background: '#dc3545', borderColor: '#dc3545' }} onClick={executeDelete}>Xóa dữ liệu</button>
                        </>
                    }
                >
                    <div style={{ padding: '20px 0', textAlign: 'center' }}>
                        <div style={{ color: '#dc3545', marginBottom: '16px' }}>
                            <svg width="64" height="64" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M10.29 3.86L1.82 18a2 2 0 0 0 1.71 3h16.94a2 2 0 0 0 1.71-3L13.71 3.86a2 2 0 0 0-3.42 0z"></path><line x1="12" y1="9" x2="12" y2="13"></line><line x1="12" y1="17" x2="12.01" y2="17"></line></svg>
                        </div>
                        <h3 style={{ fontSize: '18px', color: 'var(--text-main)', marginBottom: '8px' }}>Bạn có chắc chắn muốn xóa bản ghi này?</h3>
                        <p style={{ color: 'var(--text-muted)', fontSize: '15px', lineHeight: '1.5' }}>Hành động này không thể hoàn tác.<br/>Dữ liệu sẽ bị xóa vĩnh viễn khỏi hệ thống.</p>
                    </div>
                </Modal>
            )}
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { Ico } from './Icons';
import { initials } from './Shared';

const PAGE_LABELS = {
    dashboard: 'Tổng quan', employees: 'Nhân viên', positions: 'Chức vụ',
    suppliers: 'Nhà cung cấp', products: 'Sản phẩm', categories: 'Loại sản phẩm',
    invoices: 'Hóa đơn / Bán hàng', vouchers: 'Phiếu nhập / Hủy',
    customers: 'Khách hàng', voucher_promo: 'Voucher', promotions: 'Khuyến mãi / Giảm giá',
    accounts: 'Tài khoản', reports: 'Báo cáo doanh thu',
};

export const Topbar = ({ page, user, onLogout, collapsed, setCollapsed }) => {
    const [open, setOpen] = useState(false);
    const ref = useRef(null);
    useEffect(() => {
        const h = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
        document.addEventListener('mousedown', h);
        return () => document.removeEventListener('mousedown', h);
    }, []);
    return (
        <header className="manage-topbar">
            <div className="topbar-logo">
                <div className="topbar-logo-icon">
                    <svg width="16" height="16" viewBox="0 0 16 16" fill="none">
                        <path d="M2 6h12M2 9h8M2 12h11" stroke="#111" strokeWidth="1.7" strokeLinecap="round" />
                    </svg>
                </div>
                <span className="topbar-logo-name">MiniMart</span>
            </div>
            <div className="topbar-divider" />
            <span className="topbar-page-title">{PAGE_LABELS[page] || ''}</span>
            <div className="topbar-spacer" />
            <div ref={ref} className={`topbar-admin ${open ? 'open' : ''}`} onClick={() => setOpen(o => !o)}>
                <div className="topbar-avatar">{initials(user?.TENNV || '')}</div>
                <span className="topbar-admin-name">{user?.TENNV || ''}</span>
                <span className="topbar-admin-caret">{Ico.caret}</span>
                {open && (
                    <div className="admin-dropdown" onClick={e => e.stopPropagation()}>
                        <div className="admin-dd-header">
                            <div className="admin-dd-avatar">{initials(user?.TENNV || '')}</div>
                            <div>
                                <div className="admin-dd-name">{user?.TENNV || ''}</div>
                                <div className="admin-dd-role">{user?.chucVu?.TENCHUCVU}</div>
                                <div className="admin-dd-online">Đang hoạt động</div>
                            </div>
                        </div>
                        <div className="admin-dd-body">
                            <div className="admin-dd-row"><span style={{ color: 'var(--text-muted)' }}>{Ico.userIco}</span><span>{user?.EMAIL || ''}</span></div>
                            <div className="admin-dd-row"><span style={{ color: 'var(--text-muted)' }}>{Ico.key}</span><span>Đổi mật khẩu</span></div>
                            <div className="admin-dd-sep" />
                            <div className="admin-dd-row danger" onClick={onLogout} style={{ cursor: 'pointer' }}><span>{Ico.logout}</span><span>Đăng xuất</span></div>
                        </div>
                    </div>
                )}
            </div>
        </header>
    );
};

import React from 'react';
import { Ico } from '../../components/Manage/Icons';
import { accountService } from '../../services/accountService';

export const AccountActions = ({ item, openEdit, del, list, setList, addToast, openView }) => {

    // Toggle User Lock Status
    const toggleLock = async () => {
        try {
            await accountService.update(item.SOTK, { KHOA_TK: !item.KHOA_TK });
            setList(prev => prev.map(x => x.SOTK === item.SOTK ? { ...x, KHOA_TK: !x.KHOA_TK } : x));
            addToast('success', item.KHOA_TK ? 'Đã mở khóa tài khoản' : 'Đã khóa tài khoản');
        } catch (err) {
            console.error('Lỗi khóa tài khoản', err);
            addToast('error', 'Chỉ tài khoản Quản Trị Hệ Thống / Chủ Siêu Thị mới có quyền này');
        }
    };

    return (
        <div className="actions-cell">
            <button className="btn-action-ico" title="Xem chi tiết" onClick={() => openView && openView(item)}>{Ico.eye}</button>
            <button 
                className="btn-action-ico" 
                title={item.KHOA_TK ? "Mở khóa tài khoản" : "Khóa tài khoản"} 
                onClick={toggleLock}
            >
                {item.KHOA_TK ? Ico.unlock : Ico.lock}
            </button>
            <button className="btn-action-ico btn-edit" title="Sửa" onClick={() => openEdit(item)}>{Ico.edit}</button>
            <button className="btn-action-ico btn-del" title="Xóa" onClick={() => del(item.SOTK)}>{Ico.trash}</button>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Ico } from '../../components/Manage/Icons';
import api from '../../services/api';

export const emptyAccount = {
    TENTK: '',
    EMAIL: '',
    MANV: '',
    KHOA_TK: false,
    MATKHAU: ''
};

export const AccountForm = ({ form, hc, setForm }) => {
    const [employees, setEmployees] = useState([]);

    useEffect(() => {
        api.get('/employees')
            .then(res => setEmployees(res.data.data || res.data))
            .catch(console.error);
    }, []);

    return (
        <div className="form-grid">
            {/* ── Section: Thông tin đăng nhập ── */}
            <div className="form-section-title">
                {Ico.user} Thông tin đăng nhập
            </div>

            <div className="form-row">
                <div className="form-group">
                    <label className="form-label">Tên đăng nhập *</label>
                    <input
                        className="form-input"
                        name="TENTK"
                        value={form.TENTK}
                        onChange={hc}
                        placeholder="vd: nhanvien01"
                        autoComplete="off"
                    />
                </div>
                <div className="form-group">
                    <label className="form-label">Email *</label>
                    <input
                        className="form-input"
                        type="email"
                        name="EMAIL"
                        value={form.EMAIL}
                        onChange={hc}
                        placeholder="vd: nv@sieuthi.vn"
                    />
                </div>
            </div>

            <div className="form-group">
                <label className="form-label">Mật khẩu {form.TENTK ? '' : '*'}</label>
                <input
                    className="form-input"
                    type="password"
                    name="MATKHAU"
                    value={form.MATKHAU}
                    onChange={hc}
                    placeholder={form.TENTK ? '••••••• (bỏ trống = không đổi)' : '••••••• (ít nhất 6 ký tự)'}
                    autoComplete="new-password"
                />
            </div>

            {/* ── Section: Liên kết nhân viên ── */}
            <div className="form-section-title" style={{ marginTop: 4 }}>
                {Ico.user} Liên kết nhân viên
            </div>

            <div className="form-group">
                <label className="form-label">Nhân viên sở hữu tài khoản *</label>
                <select
                    className="form-select"
                    name="MANV"
                    value={form.MANV}
                    onChange={hc}
                >
                    <option value="">-- Chọn nhân viên --</option>
                    {employees.map(e => (
                        <option key={e.MANV} value={e.MANV}>
                            #{e.MANV} · {e.TENNV} {e.SODIENTHOAI ? `(${e.SODIENTHOAI})` : ''}
                        </option>
                    ))}
                </select>
            </div>

            {/* ── Toggle: Khoá tài khoản ── */}
            <label className="form-toggle-row" htmlFor="chk-lock">
                <div className="form-toggle-info">
                    <span className="form-toggle-label">Khoá tài khoản</span>
                    <span className="form-toggle-desc">Tài khoản bị khoá sẽ không thể đăng nhập</span>
                </div>
                <input
                    type="checkbox"
                    id="chk-lock"
                    name="KHOA_TK"
                    checked={!!form.KHOA_TK}
                    onChange={hc}
                    className="form-checkbox"
                />
            </label>
        </div>
    );
};

import React from 'react';
import { Ico } from '../../components/Manage/Icons';
import { avatarColor } from '../../components/Manage/Shared';
import { accountService } from '../../services/accountService';

export const AccountGridItem = ({ item, openEdit, del, idx, list, setList, addToast }) => {

    const toggleLock = async () => {
        try {
            await accountService.update(item.SOTK, { KHOA_TK: !item.KHOA_TK });
            setList(prev => prev.map(x => x.SOTK === item.SOTK ? { ...x, KHOA_TK: !x.KHOA_TK } : x));
            addToast('success', item.KHOA_TK ? 'Đã mở khóa tài khoản' : 'Đã khóa tài khoản');
        } catch (err) {
            console.error('Lỗi', err);
            addToast('error', 'Bạn không có quyền thực hiện hành động này');
        }
    };

    return (
        <div className={`grid-item-card account-card ${item.KHOA_TK ? 'account-locked' : ''}`}>
            <div className="grid-item-card-top">
                <div className="grid-item-icon-box" style={{ background: avatarColor(idx), color: '#fff' }}>
                    {Ico.user}
                </div>
                <span className={item.KHOA_TK ? 'badge badge-inactive' : 'badge badge-active'}>
                    {item.KHOA_TK ? 'Đã khóa' : 'Hoạt động'}
                </span>
            </div>

            <div className="grid-item-card-mid" style={{ flex: 1 }}>
                <div className="grid-item-title" style={{ fontFamily: 'var(--font)', fontSize: 15 }}>
                    {item.TENTK}
                </div>
                <div className="grid-item-label account-email">
                    {item.EMAIL || 'Chưa cập nhật email'}
                </div>
            </div>

            <div className="grid-item-card-bottom">
                <div className="grid-item-label">NV: {item.NHANVIEN?.TENNV || '—'}</div>
                <div className="grid-item-label" style={{ color: item.MATKHAU ? 'var(--green)' : 'var(--accent2)' }}>
                    {item.MATKHAU ? 'Đã thiết lập' : 'Cần cài mật khẩu'}
                </div>
            </div>

            <div className="grid-item-actions">
                <button 
                    className={`btn-edit btn-account-toggle ${item.KHOA_TK ? 'is-locked' : ''}`} 
                    title="Khóa/Mở Khóa"
                    onClick={toggleLock}
                >
                    {item.KHOA_TK ? Ico.power : Ico.ban}
                </button>
                <button className="btn-edit" title="Sửa" onClick={() => openEdit(item)}>
                    {Ico.edit}
                </button>
                <button className="btn-del" title="Xóa" onClick={() => del(item.SOTK)}>
                    {Ico.trash}
                </button>
            </div>
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import Header from '../../components/layout/Header/Header.jsx';
import './Cashier.css';

// ════════════════════════════════════════════════════════════
// HELPERS
// ════════════════════════════════════════════════════════════
const fmtVND = (v) => Number(v || 0).toLocaleString('vi-VN') + ' ₫';
const fmtDate = (d) => d ? new Date(d).toLocaleDateString('vi-VN') : '—';
const STOCK_MAX = 300;

// HINHTHUC values (HoaDon.HINHTHUC)
const HINHTHUC_MAP = {
    TIEN_MAT: { label: 'Tiền mặt' },
    THE: { label: 'Thẻ' },
    CHUYEN_KHOAN: { label: 'Chuyển khoản' },
};

// Derived order status (from IS_DELETED + HINHTHUC + business logic)
// PAID     = có HINHTHUC và IS_DELETED=false
// PENDING  = chưa có HINHTHUC và IS_DELETED=false
// CANCELLED= IS_DELETED=true
const getOrderStatus = (hd) => {
    if (hd.IS_DELETED) return 'CANCELLED';
    if (hd.HINHTHUC) return 'PAID';
    return 'PENDING';
};
const STATUS_MAP = {
    PAID: { label: 'Đã thanh toán', cls: 'badge badge-paid' },
    PENDING: { label: 'Chờ duyệt', cls: 'badge badge-pending' },
    CANCELLED: { label: 'Đã hủy', cls: 'badge badge-cancelled' },
};

const totalStock = (tonKhos = []) =>
    tonKhos.filter(t => t.IS_ACTIVE !== false)
        .reduce((s, t) => s + (t.SOLUONG_CON_LAI || 0), 0);

// ════════════════════════════════════════════════════════════
// PAGE 1: TẠO ĐƠN HÀNG
// SanPham: MASP, BARCODE, TENSP, DVT, GIABAN, MALOAI, IS_DELETED
// TonKho:  ID, MASP, SOLUONG_CON_LAI, IS_ACTIVE
// CTHoaDon: MAHD, MASP, ID_TONKHO, SOLUONG, GIABAN_GOC,
//           GIABAN_THUCTE, THANHTIEN
// HoaDon:  MAHD, NGAYHD, HINHTHUC, TONGTIEN_HANG,
//          TIEN_GIAM_VOUCHER, TONG_THANHTOAN, MANV, MAKH
// ════════════════════════════════════════════════════════════
const TaoDoPage = ({ onOrderCreated }) => {
    // TODO: fetch từ API /products?with=tonKhos,giamGias,loaiSanPham
    const [products] = useState([]);
    const [search, setSearch] = useState('');
    // cart item shape: { MASP, TENSP, BARCODE, DVT, GIABAN_GOC,
    //                   GIABAN_THUCTE, SOLUONG, THANHTIEN, ID_TONKHO }
    const [cart, setCart] = useState([]);
    const [sovoucher, setSovoucher] = useState('');

    const filtered = useMemo(() => {
        const q = search.toLowerCase();
        return products.filter(p =>
            !p.IS_DELETED &&
            (p.TENSP.toLowerCase().includes(q) || p.BARCODE.toLowerCase().includes(q))
        );
    }, [products, search]);

    const addToCart = (sp) => {
        const stock = totalStock(sp.tonKhos);
        if (stock === 0) return;

        // Tính giá thực tế (có thể check giamGias nếu có)
        const activeDiscount = sp.giamGias?.find(g =>
            g.TRANGTHAI && !g.IS_DELETED &&
            new Date(g.NGAYBD) <= new Date() && new Date(g.NGAYKT) >= new Date()
        );
        let giaBanThucTe = Number(sp.GIABAN);
        if (activeDiscount) {
            giaBanThucTe = activeDiscount.LOAI_GIAM === 0
                ? sp.GIABAN * (1 - activeDiscount.GIATRI_GIAM / 100)
                : Math.max(0, sp.GIABAN - activeDiscount.GIATRI_GIAM);
        }

        // Lấy ID_TONKHO từ lô hàng còn hạn sử dụng gần nhất
        const activeLot = sp.tonKhos
            ?.filter(t => t.IS_ACTIVE !== false && t.SOLUONG_CON_LAI > 0)
            ?.sort((a, b) => new Date(a.HANSUDUNG || '9999') - new Date(b.HANSUDUNG || '9999'))[0];

        setCart(prev => {
            const existing = prev.find(c => c.MASP === sp.MASP);
            if (existing) {
                return prev.map(c => c.MASP === sp.MASP
                    ? { ...c, SOLUONG: c.SOLUONG + 1, THANHTIEN: (c.SOLUONG + 1) * c.GIABAN_THUCTE }
                    : c
                );
            }
            return [...prev, {
                MASP: sp.MASP,
                TENSP: sp.TENSP,
                BARCODE: sp.BARCODE,
                DVT: sp.DVT,
                GIABAN_GOC: Number(sp.GIABAN),
                GIABAN_THUCTE: giaBanThucTe,
                SOLUONG: 1,
                THANHTIEN: giaBanThucTe,
                ID_TONKHO: activeLot?.ID ?? null,
            }];
        });
    };

    const changeQty = (MASP, delta) => {
        setCart(prev =>
            prev.map(c => {
                if (c.MASP !== MASP) return c;
                const newQty = c.SOLUONG + delta;
                if (newQty <= 0) return null;
                return { ...c, SOLUONG: newQty, THANHTIEN: newQty * c.GIABAN_THUCTE };
            }).filter(Boolean)
        );
    };

    const removeFromCart = (MASP) => setCart(prev => prev.filter(c => c.MASP !== MASP));

    const TONGTIEN_HANG = cart.reduce((s, c) => s + c.THANHTIEN, 0);
    const TONG_THANHTOAN = TONGTIEN_HANG; // voucher deducted on confirm

    const handleSubmitOrder = () => {
        if (cart.length === 0) return;
        // TODO: POST /orders với body:
        // { NGAYHD: now, MANV: currentUser.MANV, MAKH: null, SOVOUCHER: sovoucher||null,
        //   TONGTIEN_HANG, TIEN_GIAM_VOUCHER: 0, TONG_THANHTOAN,
        //   chiTiets: cart.map(c => ({ MASP:c.MASP, ID_TONKHO:c.ID_TONKHO,
        //               SOLUONG:c.SOLUONG, GIABAN_GOC:c.GIABAN_GOC,
        //               GIABAN_THUCTE:c.GIABAN_THUCTE, THANHTIEN:c.THANHTIEN })) }
        if (onOrderCreated) onOrderCreated();
        setCart([]);
        setSovoucher('');
    };

    return (
        <>
            <div className="c-page-header">
                <div className="c-page-title-block">
                    <div>
                        <div className="c-page-title">Tạo đơn hàng</div>
                        <div className="c-page-sub">Thêm sản phẩm vào giỏ</div>
                    </div>
                </div>
            </div>

            <div className="create-order-layout">
                {/* Left: product search + grid */}
                <div>
                    <div className="c-search-wrap">
                        <input
                            value={search}
                            onChange={e => setSearch(e.target.value)}
                            placeholder="Tìm sản phẩm..."
                        />
                    </div>
                    {filtered.length === 0 && products.length === 0 && (
                        <div style={{ textAlign: 'center', padding: 40, color: 'var(--c-text-muted)' }}>

                        </div>
                    )}
                    <div className="product-grid">
                        {filtered.map((sp, idx) => {
                            const stock = totalStock(sp.tonKhos);
                            const activeDiscount = sp.giamGias?.find(g =>
                                g.TRANGTHAI && !g.IS_DELETED &&
                                new Date(g.NGAYBD) <= new Date() && new Date(g.NGAYKT) >= new Date()
                            );
                            return (
                                <div
                                    key={sp.MASP}
                                    className={`product-card${stock === 0 ? ' out-of-stock' : ''}`}
                                    onClick={() => addToCart(sp)}
                                >
                                    {activeDiscount && (
                                        <span className="product-card-discount">
                                            {activeDiscount.LOAI_GIAM === 0
                                                ? `-${activeDiscount.GIATRI_GIAM}%`
                                                : `-${fmtVND(activeDiscount.GIATRI_GIAM)}`}
                                        </span>
                                    )}
                                    <div className="product-card-name">{sp.TENSP}</div>
                                    <div className="product-card-barcode">{sp.BARCODE}</div>
                                    <div className="product-card-footer">
                                        <span className="product-card-price">{fmtVND(sp.GIABAN)}</span>
                                        <span className={`product-card-stock${stock <= 10 ? ' low' : ''}`}>
                                            {stock === 0 ? 'Hết' : stock}
                                        </span>
                                    </div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Right: cart */}
                <div className="cart-panel">
                    <div className="cart-title">Giỏ hàng ({cart.length} SP)</div>
                    {cart.length === 0
                        ? <div className="cart-empty">Chưa có sản phẩm </div>
                        : (
                            <>
                                <div className="cart-items">
                                    {cart.map(item => (
                                        <div key={item.MASP} className="cart-item">
                                            <div className="cart-item-info">
                                                <div className="cart-item-name">{item.TENSP}</div>
                                                <div className="cart-item-price">{fmtVND(item.GIABAN_THUCTE)} / {item.DVT}</div>
                                            </div>
                                            <div className="cart-item-ctrl">
                                                <button className="qty-btn" onClick={() => changeQty(item.MASP, -1)}>−</button>
                                                <span className="qty-val">{item.SOLUONG}</span>
                                                <button className="qty-btn" onClick={() => changeQty(item.MASP, +1)}>+</button>
                                            </div>
                                            <div className="cart-item-subtotal">{fmtVND(item.THANHTIEN)}</div>
                                            <button className="cart-item-remove" onClick={() => removeFromCart(item.MASP)}>✕</button>
                                        </div>
                                    ))}
                                </div>
                                <div className="cart-footer">
                                    <div className="cart-summary-row">
                                        <span>Tạm tính</span>
                                        <span>{fmtVND(TONGTIEN_HANG)}</span>
                                    </div>
                                    <div className="cart-summary-row">
                                        {/* SOVOUCHER: mã voucher áp dụng cho HoaDon */}
                                        <span>Mã voucher (SOVOUCHER)</span>
                                        <input
                                            value={sovoucher}
                                            onChange={e => setSovoucher(e.target.value.toUpperCase())}
                                            placeholder="Nhập mã..."
                                            style={{
                                                background: 'var(--c-bg-card2)', border: '1px solid var(--c-border)',
                                                borderRadius: 6, padding: '3px 8px', color: 'var(--c-text)',
                                                fontSize: 12, width: 100
                                            }}
                                        />
                                    </div>
                                    <div className="cart-summary-row total">
                                        <span>Tổng thanh toán</span>
                                        <span className="teal">{fmtVND(TONG_THANHTOAN)}</span>
                                    </div>
                                    <div className="cart-actions">
                                        <button className="btn-primary" onClick={handleSubmitOrder}>
                                            Tạo đơn hàng
                                        </button>
                                        <button className="btn-secondary" onClick={() => setCart([])}>
                                            Xóa giỏ hàng
                                        </button>
                                    </div>
                                </div>
                            </>
                        )
                    }
                </div>
            </div>
        </>
    );
};

// ════════════════════════════════════════════════════════════
// PAGE 2: XEM TỒN KHO
// SanPham + TonKho + LoaiSanPham
// ════════════════════════════════════════════════════════════
const TonKhoPage = () => {
    // TODO: fetch từ API /products?with=tonKhos,loaiSanPham
    const [products] = useState([]);
    const [search, setSearch] = useState('');

    const filtered = useMemo(() => {
        const q = search.toLowerCase();
        return products.filter(p =>
            !p.IS_DELETED &&
            (p.TENSP.toLowerCase().includes(q) || p.BARCODE.toLowerCase().includes(q))
        );
    }, [products, search]);

    const getStockStatus = (stock) => {
        if (stock === 0) return { cls: 'badge-out', label: 'Hết hàng', barCls: 'out' };
        if (stock <= 10) return { cls: 'badge-low', label: 'Sắp hết', barCls: 'low' };
        return { cls: 'badge-in-stock', label: 'Còn hàng', barCls: '' };
    };

    return (
        <>
            <div className="c-page-header">
                <div className="c-page-title-block">
                    <div>
                        <div className="c-page-title">Xem tồn kho</div>
                        <div className="c-page-sub">Tra cứu nhanh số lượng hàng</div>
                    </div>
                </div>
            </div>

            <div className="c-search-wrap">
                <input value={search} onChange={e => setSearch(e.target.value)} placeholder="Tìm sản phẩm..." />
            </div>

            <div className="c-data-card">
                <table className="c-table">
                    <thead>
                        <tr>
                            <th>Sản phẩm</th>
                            <th>Danh mục</th>
                            <th>Đơn giá</th>
                            <th>Tồn kho</th>
                            <th>Tình trạng</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filtered.length === 0 && (
                            <tr className="empty-row"><td colSpan={5}> </td></tr>
                        )}
                        {filtered.map(sp => {
                            const stock = totalStock(sp.tonKhos);
                            const pct = Math.min(100, Math.round((stock / STOCK_MAX) * 100));
                            const st = getStockStatus(stock);
                            return (
                                <tr key={sp.MASP}>
                                    <td>
                                        <div className="entity-name">{sp.TENSP}</div>
                                        <div className="entity-sub">{sp.BARCODE}</div>
                                    </td>
                                    <td style={{ color: 'var(--c-text-sub)', fontSize: 13 }}>
                                        {sp.loaiSanPham?.TENLOAI || '—'}
                                    </td>
                                    <td className="price-teal">{fmtVND(sp.GIABAN)}</td>
                                    <td>
                                        <div className="stock-bar-wrap">
                                            <div className="stock-bar">
                                                <div className={`stock-fill ${st.barCls}`} style={{ width: `${pct}%` }} />
                                            </div>
                                            <span className="stock-count">{stock}</span>
                                        </div>
                                    </td>
                                    <td><span className={`badge ${st.cls}`}>{st.label}</span></td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        </>
    );
};

// ════════════════════════════════════════════════════════════
// PAGE 3: DANH SÁCH ĐƠN HÀNG
// HoaDon: MAHD, NGAYHD, HINHTHUC, TONGTIEN_HANG,
//         TIEN_GIAM_VOUCHER, TONG_THANHTOAN, MANV, MAKH, IS_DELETED
// joined: nhanVien.TENNV, khachHang.TENKH, chiTiets[]
// ════════════════════════════════════════════════════════════
const DanhSachDonPage = () => {
    // TODO: fetch từ API /orders?with=nhanVien,khachHang,chiTiets
    const [orders, setOrders] = useState([]);
    const [modalOrder, setModalOrder] = useState(null);

    const handleCancel = (MAHD) => {
        // TODO: PATCH /orders/:MAHD với { IS_DELETED: true }
        if (window.confirm('Hủy đơn hàng này?')) {
            setOrders(prev => prev.map(o => o.MAHD === MAHD ? { ...o, IS_DELETED: true } : o));
        }
    };

    return (
        <>
            <div className="c-page-header">
                <div className="c-page-title-block">
                    <div>
                        <div className="c-page-title">Danh sách đơn hàng</div>
                        <div className="c-page-sub">{orders.length} đơn</div>
                    </div>
                </div>
            </div>

            <div className="c-data-card">
                <table className="c-table">
                    <thead>
                        <tr>
                            <th>Mã đơn</th>
                            <th>Ngày</th>
                            <th>Thu ngân</th>
                            <th>Tổng</th>
                            <th>TT</th>
                            <th>Trạng thái</th>
                            <th></th>
                        </tr>
                    </thead>
                    <tbody>
                        {orders.length === 0 && (
                            <tr className="empty-row"><td colSpan={7}></td></tr>
                        )}
                        {orders.map(o => {
                            const status = getOrderStatus(o);
                            const st = STATUS_MAP[status];
                            const ht = HINHTHUC_MAP[o.HINHTHUC];
                            return (
                                <tr key={o.MAHD}>
                                    <td>
                                        <span className="c-code-link" onClick={() => setModalOrder(o)}>
                                            ORD-{String(o.MAHD).padStart(3, '0')}
                                        </span>
                                    </td>
                                    <td style={{ color: 'var(--c-text-sub)', fontSize: 13 }}>{fmtDate(o.NGAYHD)}</td>
                                    <td style={{ fontSize: 13 }}>{o.nhanVien?.TENNV || '—'}</td>
                                    <td className="price-teal">{fmtVND(o.TONG_THANHTOAN)}</td>
                                    <td>
                                        {ht
                                            ? <div className="hinhthuc-cell">{ht.label}</div>
                                            : <span style={{ color: 'var(--c-text-muted)' }}>—</span>}
                                    </td>
                                    <td><span className={st.cls}>{st.label}</span></td>
                                    <td>
                                        <div className="actions-cell">
                                            <button className="btn-view" onClick={() => setModalOrder(o)}>Xem</button>
                                            {status === 'PENDING' && (
                                                <button className="btn-cancel" onClick={() => handleCancel(o.MAHD)}>Hủy</button>
                                            )}
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>

            {/* Modal: Chi tiết đơn hàng */}
            {modalOrder && (
                <div className="modal-overlay" onClick={() => setModalOrder(null)}>
                    <div className="modal-box" onClick={e => e.stopPropagation()}>
                        <div className="modal-title">
                            Chi tiết — ORD-{String(modalOrder.MAHD).padStart(3, '0')}
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Ngày lập (NGAYHD)</span>
                            <span className="modal-detail-value">{fmtDate(modalOrder.NGAYHD)}</span>
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Thu ngân (MANV)</span>
                            <span className="modal-detail-value">{modalOrder.nhanVien?.TENNV || modalOrder.MANV}</span>
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Khách hàng (MAKH)</span>
                            <span className="modal-detail-value">{modalOrder.khachHang?.TENKH || 'Khách lẻ'}</span>
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Hình thức TT (HINHTHUC)</span>
                            <span className="modal-detail-value">
                                {HINHTHUC_MAP[modalOrder.HINHTHUC]
                                    ? HINHTHUC_MAP[modalOrder.HINHTHUC].label
                                    : '—'}
                            </span>
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Tổng tiền hàng (TONGTIEN_HANG)</span>
                            <span className="modal-detail-value">{fmtVND(modalOrder.TONGTIEN_HANG)}</span>
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Giảm voucher (TIEN_GIAM_VOUCHER)</span>
                            <span className="modal-detail-value" style={{ color: 'var(--c-red)' }}>
                                -{fmtVND(modalOrder.TIEN_GIAM_VOUCHER)}
                            </span>
                        </div>
                        <div className="modal-detail-row">
                            <span className="modal-detail-label">Tổng thanh toán (TONG_THANHTOAN)</span>
                            <span className="modal-detail-value" style={{ color: 'var(--c-teal)', fontSize: 16 }}>
                                {fmtVND(modalOrder.TONG_THANHTOAN)}
                            </span>
                        </div>

                        {/* Chi tiết từng sản phẩm (CTHoaDon) */}
                        {(modalOrder.chiTiets?.length > 0) && (
                            <>
                                <div style={{ margin: '18px 0 10px', fontWeight: 700, color: 'var(--c-text)', fontSize: 14 }}>
                                    Chi tiết sản phẩm
                                </div>
                                {modalOrder.chiTiets.map((ct, i) => (
                                    <div key={i} className="modal-detail-row">
                                        <span className="modal-detail-label">
                                            {ct.sanPham?.TENSP || `SP #${ct.MASP}`} × {ct.SOLUONG}
                                        </span>
                                        <span className="modal-detail-value">{fmtVND(ct.THANHTIEN)}</span>
                                    </div>
                                ))}
                            </>
                        )}

                        <div className="modal-actions">
                            <button className="btn-secondary" onClick={() => setModalOrder(null)}>Đóng</button>
                        </div>
                    </div>
                </div>
            )}
        </>
    );
};

// ════════════════════════════════════════════════════════════
// PAGE 4: THANH TOÁN
// Chọn đơn PENDING → nhập HINHTHUC → xác nhận
// Cập nhật HoaDon: { HINHTHUC, TONG_THANHTOAN }
// ════════════════════════════════════════════════════════════
const ThanhToanPage = () => {
    // TODO: fetch từ API /orders?status=pending&with=chiTiets,nhanVien
    const [pendingOrders] = useState([]);
    const [selectedOrder, setSelectedOrder] = useState(null);
    const [hinhThuc, setHinhThuc] = useState('');

    const handleConfirmPayment = () => {
        if (!selectedOrder || !hinhThuc) return;
        // TODO: PATCH /orders/:MAHD với:
        // { HINHTHUC: hinhThuc, TONG_THANHTOAN: selectedOrder.TONG_THANHTOAN }
        alert(`Xác nhận thanh toán ORD-${String(selectedOrder.MAHD).padStart(3, '0')} bằng ${HINHTHUC_MAP[hinhThuc]?.label}`);
        setSelectedOrder(null);
        setHinhThuc('');
    };

    return (
        <>
            <div className="c-page-header">
                <div className="c-page-title-block">
                    <div>
                        <div className="c-page-title">Thanh toán</div>
                        <div className="c-page-sub">Chọn đơn và xử lý thanh toán</div>
                    </div>
                </div>
            </div>

            <div className="payment-layout">
                {/* Left: pending orders */}
                <div className="payment-panel">
                    <div className="payment-panel-title">Đơn chờ thanh toán</div>
                    {pendingOrders.length === 0 && (
                        <div className="payment-placeholder"></div>
                    )}
                    {pendingOrders.map(o => (
                        <div
                            key={o.MAHD}
                            className={`pending-order-item${selectedOrder?.MAHD === o.MAHD ? ' selected' : ''}`}
                            onClick={() => { setSelectedOrder(o); setHinhThuc(''); }}
                        >
                            <div className="pending-order-id">ORD-{String(o.MAHD).padStart(3, '0')}</div>
                            <div className="pending-order-sub">
                                {o.nhanVien?.TENNV || '—'} · {o.chiTiets?.length || 0} sản phẩm
                            </div>
                            <div className="pending-order-total">{fmtVND(o.TONG_THANHTOAN)}</div>
                        </div>
                    ))}
                </div>

                {/* Right: payment info */}
                <div className="payment-panel">
                    <div className="payment-panel-title">Thông tin thanh toán</div>
                    {!selectedOrder
                        ? <div className="payment-placeholder"></div>
                        : (
                            <>
                                <div className="pay-detail-row">
                                    <span className="pay-detail-label">Mã đơn (MAHD)</span>
                                    <span className="pay-detail-value">ORD-{String(selectedOrder.MAHD).padStart(3, '0')}</span>
                                </div>
                                <div className="pay-detail-row">
                                    <span className="pay-detail-label">Ngày lập (NGAYHD)</span>
                                    <span className="pay-detail-value">{fmtDate(selectedOrder.NGAYHD)}</span>
                                </div>
                                <div className="pay-detail-row">
                                    <span className="pay-detail-label">Tổng tiền hàng (TONGTIEN_HANG)</span>
