export const PromotionActions = ({ item, openEdit, del, list, setList, addToast, openView }) => {

    // Toggle Status
    const toggleStatus = async () => {
        try {
            await promotionService.update(item.ID, { ...item, TRANGTHAI: !item.TRANGTHAI });
            setList(prev => prev.map(x => x.ID === item.ID ? { ...x, TRANGTHAI: !x.TRANGTHAI } : x));
            addToast('success', !item.TRANGTHAI ? 'Đã kích hoạt khuyến mãi' : 'Đã tạm dừng khuyến mãi');
        } catch (err) {
            console.error('Lỗi cập nhật trạng thái', err);
            addToast('error', 'Không thể thay đổi trạng thái lúc này');
        }
    };

    return (
        <div className="actions-cell">
            <button className="btn-action-ico" title="Xem chi tiết" onClick={() => openView && openView(item)}>{Ico.eye}</button>
            <button 
                className="btn-action-ico" 
                title={item.TRANGTHAI ? "Khóa/Tạm dừng chương trình" : "Kích hoạt chương trình"} 
                onClick={toggleStatus}
            >
                {item.TRANGTHAI ? Ico.lock : Ico.unlock}
            </button>
            <button className="btn-action-ico btn-edit" title="Sửa" onClick={() => openEdit(item)}>{Ico.edit}</button>
            <button className="btn-action-ico btn-del" title="Xóa" onClick={() => del(item.ID)}>{Ico.trash}</button>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Ico } from '../../components/Manage/Icons';
